function normalizeRiskLevel(value, score) {
  if (value) {
    const v = String(value).toUpperCase();

    if (v.includes("LOW")) return "LOW";
    if (v.includes("MEDIUM") || v.includes("MODERATE")) return "MEDIUM";
    if (v.includes("HIGH")) return "HIGH";
  }

  const numericScore = Number(score || 0);

  if (numericScore >= 80) return "LOW";
  if (numericScore >= 60) return "MEDIUM";
  return "HIGH";
}

function score(value) {
  return Number(value || 0);
}

function uniqueArray(arr) {
  return [...new Set(arr.filter(Boolean))];
}

const release = $json.releaseData || {};

const securityAI = $json.securityAI || {};
const performanceAI = $json.performanceAI || {};
const businessAI = $json.businessAI || {};
const observabilityAI = $json.observabilityAI || {};
const reliabilityAI = $json.reliabilityAI || {};
const complianceAI = $json.complianceAI || {};

const releaseMetrics = release.releaseMetrics || {};

let blockers = uniqueArray(release.criticalBlockers || []);
let actions = uniqueArray(release.requiredActionsBeforeRelease || []);

const securityScore = score(securityAI.securityScore);
const performanceScore = score(performanceAI.performanceScore);
const businessScore = score(businessAI.businessScore);
const observabilityScore = score(observabilityAI.observabilityScore);
const reliabilityScore = score(reliabilityAI.reliabilityScore);
const complianceScore = score(complianceAI.complianceScore);

const qaReadiness = score(releaseMetrics.qaReadiness);

let finalConfidence = score(release.releaseConfidenceScore);
let finalRiskLevel = release.riskLevel || "UNKNOWN";
let finalRecommendation = release.releaseRecommendation || "UNKNOWN";

if (qaReadiness <= 20) {
  finalConfidence =
    finalConfidence === 0
      ? 35
      : Math.min(finalConfidence, 50);

  finalRiskLevel = "HIGH";
  finalRecommendation = "NO_GO";

  blockers = uniqueArray([
  ...blockers.filter(
    b => !String(b).toLowerCase().includes("no testing performed")
  ),
  "No testing performed or QA coverage is critically insufficient."
]);

  actions = uniqueArray([
    ...actions,
    "Create and execute full QA coverage including functional, negative, edge-case, security, integration, and regression tests."
  ]);
}

return {
  overallRiskScore: 100 - finalConfidence,

  releaseConfidenceScore: finalConfidence,

  riskLevel: normalizeRiskLevel(finalRiskLevel, finalConfidence),

  releaseRecommendation: finalRecommendation,

  securityScore,
  performanceScore,
  businessScore,
  observabilityScore,
  reliabilityScore,
  complianceScore,

  securityRiskLevel: normalizeRiskLevel(
    securityAI.securityRiskLevel || securityAI.riskLevel,
    securityScore
  ),

  performanceRiskLevel: normalizeRiskLevel(
    performanceAI.performanceRiskLevel,
    performanceScore
  ),

  businessRiskLevel: normalizeRiskLevel(
    businessAI.businessRiskLevel,
    businessScore
  ),

  observabilityRiskLevel: normalizeRiskLevel(
    observabilityAI.observabilityRiskLevel,
    observabilityScore
  ),

  reliabilityRiskLevel: normalizeRiskLevel(
    reliabilityAI.reliabilityRiskLevel,
    reliabilityScore
  ),

  complianceRiskLevel: normalizeRiskLevel(
    complianceAI.complianceRiskLevel,
    complianceScore
  ),

  releaseMetrics,

  totalBlockers: blockers.length,

  totalActions: actions.length,

  criticalBlockers: blockers,

  requiredActions: actions,

  executiveSummary:
    qaReadiness <= 20
      ? `${release.executiveSummary || ""} QA coverage is critically insufficient, so the release is blocked until proper testing is completed.`.trim()
      : release.executiveSummary || ""
};

function cleanJson(data) {
  if (!data) return {};

  if (typeof data === 'object') {
    return data;
  }

  try {
    const cleaned = String(data)
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    return JSON.parse(cleaned);
  } catch (e) {
    return {};
  }
}

return {
  requirementAI: cleanJson($json.requirementAI),
  devAI: cleanJson($json.devAI),
  qaAI: cleanJson($json.qaAI),

  securityAI: cleanJson($json.securityAI),
  performanceAI: cleanJson($json.performanceAI),
  businessAI: cleanJson($json.businessAI),
  observabilityAI: cleanJson($json.observabilityAI),
  reliabilityAI: cleanJson($json.reliabilityAI),
  complianceAI: cleanJson($json.complianceAI)
};

const text = $json.output[0].content[0].text;

const cleaned = text
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

return {
  releaseData: JSON.parse(cleaned)
};

const now = new Date();

return {
  ...$json,

  releaseId: `REL-${now.getFullYear()}-${Date.now()}`,
  timestamp: now.toISOString(),

  requirement: $('Webhook').first().json.body?.requirement || $('Webhook').first().json.requirement || "",
  changeSummary: $('Webhook').first().json.body?.changeSummary || $('Webhook').first().json.changeSummary || "",
  testingSummary: $('Webhook').first().json.body?.testingSummary || $('Webhook').first().json.testingSummary || ""
};
